1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type Damage = { itemType: string; amount: number };
17	type Incident = { cause: string; damages: Damage[] };
18	type Step = { op: string; items?: Item[]; policy?: number; incident?: Incident };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	
21	const DEDUCTIBLE_PER_DAMAGE = 100;
22	
23	const claimStep = (step: Step): { payout: number } => {
24	  const damages = step.incident!.damages;
25	  const payout = damages.reduce((sum, d) => sum + (d.amount - DEDUCTIBLE_PER_DAMAGE), 0);
26	  return { payout };
27	};
28	
29	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
30	
31	const BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_PRICE = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const sumItemBasePremiums = (items: Item[]): number =>
37	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
38	
39	const groupByType = (items: Item[]): Map<string, Item[]> => {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	};
48	
49	const priceComponentGroup = (group: Item[]): number =>
50	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
51	
52	const computeBasePremium = (items: Item[]): number => {
53	  const components = items.filter(isComponent);
54	  const nonComponents = items.filter((item) => !isComponent(item));
55	  const componentGroups = [...groupByType(components).values()];
56	  const componentTotal = componentGroups.reduce(
57	    (sum, group) => sum + priceComponentGroup(group),
58	    0,
59	  );
60	  return sumItemBasePremiums(nonComponents) + componentTotal;
61	};
62	
63	const CURSE_SURCHARGE_RATE = 0.5;
64	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	
67	const itemSurcharge = (item: Item): number => {
68	  const base = itemBasePremium(item);
69	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
70	  const enchantment =
71	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
72	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
73	      : 0;
74	  return curse + enchantment;
75	};
76	
77	const sumItemSurcharges = (items: Item[]): number =>
78	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
79	
80	const LOYALTY_DISCOUNT_RATE = 0.2;
81	const LOYALTY_THRESHOLD_YEARS = 2;
82	
83	type Customer = { yearsWithMHPCO: number };
84	type PolicyContext = { customer: Customer; contractIndex: number };
85	
86	const loyaltyDiscount = (base: number, customer: Customer): number =>
87	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
88	
89	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
90	
91	const followUpDiscount = (base: number, contractIndex: number): number =>
92	  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
93	
94	const sumPolicyDiscounts = (base: number, ctx: PolicyContext): number =>
95	  loyaltyDiscount(base, ctx.customer) + followUpDiscount(base, ctx.contractIndex);
96	
97	const sumPolicySurcharges = (base: number): number => base * FIRST_INSURANCE_RATE;
98	
99	const quoteStep = (step: Step, ctx: PolicyContext): { premium: number } => {
100	  const items = step.items!;
101	  const base = computeBasePremium(items);
102	  const surcharges = sumItemSurcharges(items) + sumPolicySurcharges(base);
103	  const discounts = sumPolicyDiscounts(base, ctx);
104	  return {
105	    premium: Math.ceil(base + surcharges - discounts + PROCESSING_FEE),
106	  };
107	};
108	
109	export const runScenario = (scenario: unknown): unknown => {
110	  const { customer, steps } = scenario as Scenario;
111	  let contractIndex = 0;
112	  const results = steps.map((step) => {
113	    if (step.op === "claim") {
114	      return claimStep(step);
115	    }
116	    const result = quoteStep(step, { customer, contractIndex });
117	    contractIndex += 1;
118	    return result;
119	  });
120	  return { results };
121	};
